import React from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';

export default function Sidebar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const isStaff = user?.userType === 'user'; // librarian or assistant

  const navItems = [
    { path: '/dashboard', icon: '⊞', label: 'Dashboard', show: true },
    { path: '/books', icon: '📚', label: 'Books', show: true },
    { path: '/members', icon: '👥', label: 'Members', show: isStaff },
    { path: '/requests', icon: '🔔', label: 'Borrow Requests', show: isStaff },
    { path: '/borrows', icon: '↔', label: 'Borrows', show: isStaff },
    { path: '/categories', icon: '⊕', label: 'Categories', show: true },
    { path: '/my-borrows', icon: '📋', label: 'My Library', show: !isStaff },
  ];

  const roleLabel: any = {
    librarian: 'Librarian',
    library_assistant: 'Library Assistant',
    student: 'Student',
    staff: 'Staff',
  };

  const roleColor: any = {
    librarian: '#c9a84c',
    library_assistant: '#10b981',
    student: '#3b82f6',
    staff: '#8b5cf6',
  };

  return (
    <aside style={{ width: 240, minHeight: '100vh', background: '#1a1a2e', display: 'flex', flexDirection: 'column', flexShrink: 0 }}>
      <div style={{ padding: '24px 20px', borderBottom: '1px solid rgba(255,255,255,0.08)' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <div style={{ width: 38, height: 38, background: '#c9a84c', borderRadius: 9, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 18 }}>📖</div>
          <div>
            <div style={{ fontFamily: "'Playfair Display',serif", fontSize: 17, fontWeight: 700, color: '#fff' }}>LibraryMS</div>
            <div style={{ fontSize: 11, color: '#c9a84c' }}>University Library</div>
          </div>
        </div>
      </div>

      <nav style={{ flex: 1, padding: '16px 12px' }}>
        {navItems.filter(i => i.show).map(item => (
          <NavLink key={item.path} to={item.path}
            style={({ isActive }) => ({
              display: 'flex', alignItems: 'center', gap: 10, padding: '10px 14px',
              borderRadius: 10, fontSize: 14, fontWeight: isActive ? 600 : 500,
              color: isActive ? '#1a1a2e' : 'rgba(255,255,255,0.55)',
              background: isActive ? '#c9a84c' : 'transparent',
              cursor: 'pointer', textDecoration: 'none', marginBottom: 2, transition: 'all .2s',
            })}>
            <span style={{ fontSize: 15, width: 20, textAlign: 'center' }}>{item.icon}</span>
            {item.label}
          </NavLink>
        ))}
      </nav>

      <div style={{ padding: '16px 12px', borderTop: '1px solid rgba(255,255,255,0.08)' }}>
        <div style={{ background: 'rgba(255,255,255,0.06)', borderRadius: 10, padding: 12, marginBottom: 8 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
            <div style={{ width: 36, height: 36, background: roleColor[user?.role] || '#c9a84c', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 700, color: '#1a1a2e', fontSize: 14, flexShrink: 0 }}>
              {user?.name?.charAt(0)}
            </div>
            <div style={{ minWidth: 0 }}>
              <div style={{ fontSize: 13, fontWeight: 600, color: '#fff', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{user?.name}</div>
              <div style={{ fontSize: 11, color: roleColor[user?.role] || '#c9a84c' }}>{roleLabel[user?.role] || user?.role}</div>
            </div>
          </div>
          {user?.member_id && (
            <div style={{ marginTop: 8, fontSize: 11, color: 'rgba(255,255,255,0.4)', fontFamily: 'monospace' }}>ID: {user.member_id}</div>
          )}
        </div>
        <button onClick={() => { logout(); navigate('/login'); }}
          style={{ width: '100%', display: 'flex', alignItems: 'center', gap: 8, padding: '9px 14px', borderRadius: 10, fontSize: 13, color: 'rgba(255,255,255,0.55)', background: 'none', border: 'none', cursor: 'pointer', fontFamily: 'inherit' }}>
          ⎋ Sign out
        </button>
      </div>
    </aside>
  );
}
